 1	import type { ComponentType } from 'react';
 2	
 3	import {
 4	  Button,
 5	  ButtonVariant,
 6	  EmptyState,
 7	  EmptyStateActions,
 8	  EmptyStateBody,
 9	  EmptyStateFooter,
10	  EmptyStateHeader,
11	  EmptyStateIcon,
12	  Spinner,
13	  Title,
14	} from '@patternfly/react-core';
15	import { ExclamationCircleIcon, SearchIcon } from '@patternfly/react-icons';
16	
17	/**
18	 * The page basic states.
19	 *
20	 * [<img src="static/media/src/components-stories/assets/github-logo.svg"><i class="fi fi-brands-github">
21	 * <font color="green">View component source on GitHub</font>](https://github.com/kubev2v/forklift-console-plugin/blob/main/packages/common/src/components/Page/PageStates.tsx)
22	 */
23	const BaseState = ({
24	  color,
25	  icon,
26	  title,
27	}: {
28	  title?: string;
29	  icon?: ComponentType<unknown>;
30	  color?: string;
31	}) => {
32	  return (
33	    <EmptyState>
34	      <EmptyStateHeader
35	        titleText={title}
36	        headingLevel="h4"
37	        icon={icon && <EmptyStateIcon icon={icon} color={color} />}
38	      />
39	    </EmptyState>
40	  );
41	};
42	
43	export const ErrorState = ({ title }: { title: string }) => (
44	  <BaseState icon={ExclamationCircleIcon} color="#C9190B" title={title} />
45	);
46	
47	export const Loading = ({ title }: { title: string }) => <BaseState icon={Spinner} title={title} />;
48	
49	export const NoResultsFound = ({ title }: { title: string }) => (
50	  <BaseState icon={SearchIcon} title={title} />
51	);
52	
53	/**
54	 * The page for a case of no results matching a filter, including a title, description and a button for clearing all filters.
55	 *
56	 * [<img src="static/media/src/components-stories/assets/github-logo.svg"><i class="fi fi-brands-github">
57	 * <font color="green">View component source on GitHub</font>](https://github.com/kubev2v/forklift-console-plugin/blob/main/packages/common/src/components/Page/PageStates.tsx)
58	 */
59	export const NoResultsMatchFilter = ({
60	  clearAllFilters,
61	  clearAllLabel = 'Clear all filters',
62	  description = 'No results match the filter criteria. Clear all filters and try again.',
63	  title = 'No results found',
64	}: {
65	  clearAllFilters: () => void;
66	  title?: string;
67	  description?: string;
68	  clearAllLabel?: string;
69	}) => {
70	  return (
71	    <EmptyState>
72	      <EmptyStateIcon icon={SearchIcon} />
73	      <Title size="lg" headingLevel="h4">
74	        {title}
75	      </Title>
76	      <EmptyStateBody>{description}</EmptyStateBody>
77	      <EmptyStateFooter>
78	        <EmptyStateActions>
79	          <Button variant={ButtonVariant.link} onClick={clearAllFilters}>
80	            {clearAllLabel}
81	          </Button>
82	        </EmptyStateActions>
83	      </EmptyStateFooter>
84	    </EmptyState>
85	  );
86	};

